module shift_register (
    input clk,
    input reset,
    input enable,
    input serial_in,
    output reg [7:0] parallel_out
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset) begin
            parallel_out <= 8'b0;
        end else if (enable) begin
            parallel_out <= {parallel_out[6:0], serial_in};
        end
    end
endmodule
